## Problem1(1.3.8.57)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
do {
  @x = map {$_ + random(0.1,0.9,0.1)} (random_subset(2, 10 .. 80));
  @y = map {$_ + random(0.1,0.9,0.1)} (random_subset(2, 10 .. 80));
} until (($x[0] - $x[1])**2 + ($y[0] - $y[1])**2 > 100);
$m = ($y[1] - $y[0]) / ($x[1] - $x[0]);
@dir;
for (0,1) {
  if ($m > 0) {
    $dir[$_] = ($x[$_] < $x[($_ + 1) % 2]) ? 'below right' : 'above left';
  } else {
    $dir[$_] = ($x[$_] < $x[($_ + 1) % 2]) ? 'above right' : 'below left';
  }
}
Context("Numeric");
$f = Formula("$m (x - $x[0]) + $y[0]");
Context("Fraction");
@p = map {Point($x[$_], $y[$_])} (0,1);
@domain = num_sort(-10, 100, (-10 - $y[0])/$m + $x[0], (100 - $y[0])/$m + $x[0]);
($l,$r) = (@domain)[1,2];

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}[
      xmin=-10,
      xmax=100,
      ymin=-10,
      ymax=100,
      xtick=,
      minor xtick=,
      ytick=,
      minor ytick=,
      width=0.33\orccaprintwidth,
      clip=false
    ]
    \addplot+[-,domain=$l:$r,samples=2] {$f};
    \addplot[soliddot] coordinates {$p[0]} node[$dir[0]] {\($p[0]\)};
    \addplot[soliddot] coordinates {$p[1]} node[$dir[1]] {\($p[1]\)};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
Find the slope of the line given its graph.

>> [@image(insertGraph($image_1), width=>600)@]*  <<

[_]{$m}{10}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
